import React, { useState, useContext } from 'react';
import { Link } from 'react-router-dom';
import { FaComment, FaThumbsUp, FaRegThumbsUp, FaShare, FaEllipsisV } from 'react-icons/fa';
import { toast } from 'react-toastify';
import { AuthContext } from '../context/AuthContext';
import formatDate from '../utils/formatDate';
import forumService from '../services/forumService';

const ForumPostCard = ({ post, onPostUpdated }) => {
  const { user } = useContext(AuthContext);
  const [showDropdown, setShowDropdown] = useState(false);
  const [isLiked, setIsLiked] = useState(
    user && post.likes && post.likes.includes(user._id)
  );
  const [likesCount, setLikesCount] = useState(post.likes ? post.likes.length : 0);

  const handleLike = async () => {
    if (!user) {
      toast.error('Please log in to like posts');
      return;
    }

    try {
      const updatedPost = await forumService.likePost(post._id);
      setIsLiked(!isLiked);
      setLikesCount(isLiked ? likesCount - 1 : likesCount + 1);
      if (onPostUpdated) {
        onPostUpdated(updatedPost);
      }
    } catch (error) {
      toast.error('Error liking post. Please try again.');
      console.error('Error liking post:', error);
    }
  };

  const handleShare = () => {
    navigator.clipboard.writeText(`${window.location.origin}/forum/post/${post._id}`);
    toast.success('Link copied to clipboard!');
  };

  const handleDelete = async () => {
    if (!user || (user._id !== post.author._id && !user.isAdmin)) {
      toast.error('You do not have permission to delete this post');
      return;
    }

    try {
      await forumService.deletePost(post._id);
      toast.success('Post deleted successfully');
      if (onPostUpdated) {
        onPostUpdated(null, post._id);
      }
    } catch (error) {
      toast.error('Error deleting post. Please try again.');
      console.error('Error deleting post:', error);
    }
    setShowDropdown(false);
  };

  const truncateText = (text, maxLength = 150) => {
    if (!text || text.length <= maxLength) return text;
    return text.substring(0, maxLength) + '...';
  };

  return (
    <div className="bg-white dark:bg-gray-800 rounded-lg shadow-md p-4 mb-4">
      {/* Post Header */}
      <div className="flex justify-between items-center mb-3">
        <div className="flex items-center">
          <img 
            src={post.author?.profilePicture || "https://via.placeholder.com/40"} 
            alt={post.author?.name || "User"} 
            className="w-10 h-10 rounded-full mr-3"
          />
          <div>
            <h3 className="font-semibold text-gray-800 dark:text-gray-200">
              {post.author?.name || "Anonymous User"}
            </h3>
            <p className="text-xs text-gray-500 dark:text-gray-400">
              {formatDate(post.createdAt)}
              {post.category && <span className="ml-2 bg-green-100 dark:bg-green-900 text-green-800 dark:text-green-200 text-xs px-2 py-0.5 rounded-full">{post.category}</span>}
            </p>
          </div>
        </div>
        
        {user && (user._id === post.author?._id || user.isAdmin) && (
          <div className="relative">
            <button 
              onClick={() => setShowDropdown(!showDropdown)}
              className="text-gray-500 hover:text-gray-700 dark:text-gray-400 dark:hover:text-gray-200"
            >
              <FaEllipsisV />
            </button>
            
            {showDropdown && (
              <div className="absolute right-0 mt-2 w-36 bg-white dark:bg-gray-700 rounded-md shadow-lg z-10">
                <button 
                  onClick={handleDelete}
                  className="w-full text-left px-4 py-2 text-sm text-red-600 dark:text-red-400 hover:bg-gray-100 dark:hover:bg-gray-600 rounded-md"
                >
                  Delete Post
                </button>
              </div>
            )}
          </div>
        )}
      </div>
      
      {/* Post Title and Content */}
      <Link to={`/forum/post/${post._id}`} className="block">
        <h2 className="text-xl font-bold mb-2 text-gray-900 dark:text-white">{post.title}</h2>
        <p className="text-gray-700 dark:text-gray-300 mb-4">{truncateText(post.description)}</p>
        {post.description.length > 150 && (
          <span className="text-green-600 dark:text-green-400 text-sm font-medium">Read more</span>
        )}
      </Link>
      
      {/* Post Image (if available) */}
      {post.image && (
        <div className="mb-4">
          <img 
            src={post.image} 
            alt="Post attachment" 
            className="w-full h-auto rounded-lg object-cover max-h-72"
          />
        </div>
      )}
      
      {/* Post Actions */}
      <div className="flex items-center justify-between pt-3 mt-3 border-t border-gray-200 dark:border-gray-700">
        <button 
          onClick={handleLike}
          className={`flex items-center space-x-1 ${
            isLiked 
              ? 'text-green-600 dark:text-green-400' 
              : 'text-gray-500 dark:text-gray-400 hover:text-green-600 dark:hover:text-green-400'
          }`}
        >
          {isLiked ? <FaThumbsUp /> : <FaRegThumbsUp />}
          <span>{likesCount}</span>
        </button>
        
        <Link 
          to={`/forum/post/${post._id}`}
          className="flex items-center space-x-1 text-gray-500 dark:text-gray-400 hover:text-blue-600 dark:hover:text-blue-400"
        >
          <FaComment />
          <span>{post.comments ? post.comments.length : 0}</span>
        </Link>
        
        <button 
          onClick={handleShare}
          className="flex items-center space-x-1 text-gray-500 dark:text-gray-400 hover:text-purple-600 dark:hover:text-purple-400"
        >
          <FaShare />
          <span>Share</span>
        </button>
      </div>
    </div>
  );
};

export default ForumPostCard;
